"use client"
import * as React from "react"
import { cn } from "@/lib/utils"

interface AuroraBackgroundProps extends React.HTMLAttributes<HTMLDivElement> {
  colors?: string[]
  speed?: "slow" | "medium" | "fast"
  blur?: number
}

const DURATIONS = { slow: "18s", medium: "10s", fast: "5s" }

export function AuroraBackground({
  className, children,
  colors = ["#00d4ff", "#7c3aed", "#0ea5e9", "#10b981"],
  speed = "medium",
  blur = 80,
  ...props
}: AuroraBackgroundProps) {
  const dur = DURATIONS[speed]
  return (
    <div className={cn("relative overflow-hidden", className)} {...props}>
      <div className="pointer-events-none absolute inset-0" aria-hidden>
        {colors.map((color, i) => (
          <div
            key={i}
            className="absolute rounded-full opacity-20"
            style={{
              background: color,
              width: "60%",
              height: "60%",
              top: `${(i * 30) % 60}%`,
              left: `${(i * 40) % 60}%`,
              filter: `blur(${blur}px)`,
              animation: `aurora-${i % 3} ${dur} ease-in-out infinite`,
              animationDelay: `${i * (parseFloat(dur) / colors.length)}s`,
            }}
          />
        ))}
        <style>{`
          @keyframes aurora-0 {
            0%,100% { transform: translate(0,0) scale(1); }
            50% { transform: translate(10%, -15%) scale(1.1); }
          }
          @keyframes aurora-1 {
            0%,100% { transform: translate(0,0) scale(1.05); }
            50% { transform: translate(-12%, 10%) scale(0.95); }
          }
          @keyframes aurora-2 {
            0%,100% { transform: translate(0,0) scale(0.9); }
            50% { transform: translate(8%, 12%) scale(1.1); }
          }
        `}</style>
      </div>
      {children}
    </div>
  )
}
